class MedianFinder {
    priority_queue<int> lo;                              // max-heap for lower half
    priority_queue<int, vector<int>, greater<int>> hi;  // min-heap for upper half
public:
    MedianFinder() {}

    void addNum(int num) {
        lo.push(num);
        hi.push(lo.top());
        lo.pop();
        if (lo.size() < hi.size()) {
            lo.push(hi.top());
            hi.pop();
        }
    }

    double findMedian() {
        return lo.size() > hi.size() ? lo.top() : (lo.top() + hi.top()) * 0.5;
    }
};
```
efficiency: HIGH
time complexity: O(log N) addNum, O(1) findMedian
space complexity: O(N)
energy implications: LOW
explanation: Uses two heaps to partition the stream into lower and upper halves; the max-heap always contains the median or the larger half, ensuring constant-time median retrieval and logarithmic insertion.

